// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Typed player event dispatched through [`crate::observer::PlayerObserver::on_event`].
 *
 * Replaces raw integer status codes with typed enums. Swift receives
 * a single callback with a discriminated union instead of 7 separate methods.
 *
 * **Concurrency**: events may arrive from multiple threads concurrently
 * (async broadcast task + OS polling thread). Swift must handle
 * thread-safe delivery internally.
 */

public enum FfiPlayerEvent: Equatable, Hashable {

    case timeChanged(seconds: Double
    )
    case rateChanged(rate: Float
    )
    case currentItemChanged(itemId: TrackId?
    )
    case statusChanged(status: FfiPlayerStatus
    )
    case timeControlStatusChanged(status: FfiTimeControlStatus
    )
    case error(error: String
    )
    case durationChanged(seconds: Double
    )
    case bufferedDurationChanged(seconds: Double
    )
    case volumeChanged(volume: Float
    )
    case muteChanged(muted: Bool
    )
    case itemDidPlayToEnd
    /**
     * A track aborted mid-stream because the decoder / source
     * reported a non-recoverable error. Distinct from
     * [`Self::ItemDidPlayToEnd`]: the track did NOT reach its
     * natural end. UI clients should surface this as a track
     * failure (skip-and-flag), not treat it as completion.
     */
    case itemDidFail(itemId: TrackId?
    )
    /**
     * Queue-level: the loading/playback status of an item changed.
     * `item_id` is the private queue id used by the player wrapper to
     * route back to the Swift-owned item.
     */
    case trackStatusChanged(itemId: TrackId, status: FfiTrackStatus
    )
    /**
     * Queue reached the end with `RepeatMode::Off` active.
     */
    case queueEnded
    /**
     * A crossfade between tracks just started. `duration_seconds` is
     * the configured crossfade window - UIs can drive progress from it.
     */
    case crossfadeStarted(durationSeconds: Float
    )
    /**
     * The configured crossfade window changed at runtime.
     */
    case crossfadeDurationChanged(seconds: Float
    )
    case trackAdded(itemId: TrackId, index: UInt64
    )
    case trackRemoved(itemId: TrackId
    )
    case trackLoadFailed(itemId: TrackId, reason: String, autoSkipped: Bool
    )
    case repeatModeChanged(mode: FfiRepeatMode
    )
    case nextTrackReady(itemId: TrackId, index: UInt64
    )
    case currentItemAdvanced(itemId: TrackId?, reason: FfiAdvanceReason
    )
    case engineStarted
    case engineStopped
    case crossfadeCompleted
    case crossfadeCancelled
    case masterVolumeChanged(volume: Float
    )
    case audioRouteChanged(reason: FfiRouteChangeReason
    )
    case djBpmDetected(slot: UInt64, bpm: Double, confidence: Float?, firstBeatOffsetSeconds: Double
    )
    case djKeylockChanged(on: Bool
    )
    case djStretchBackendChanged(kind: FfiStretchBackendKind
    )
    case assetCommitted(assetRoot: String, relPath: String, finalLen: UInt64?
    )
    case assetFailed(assetRoot: String, relPath: String, reason: String
    )
    case assetEvicted(assetRoot: String, reason: FfiEvictReason
    )
    case transportTempoCommitted(beatsPerMinute: Double, revision: UInt64
    )
    case transportPlayStateCommitted(playing: Bool, revision: UInt64
    )
    case transportFailed(revision: UInt64?, reason: String
    )
    case syncBindingCommitted(slot: UInt64, sessionAnchorBeats: Double, trackAnchorBeats: Double, direction: FfiPlaybackDirection
    )





}

