/**
 * Track lifecycle state for a queued item.
 *
 * Emitted by the native engine as the queue loads, plays, consumes,
 * fails, or cancels an item.
 */

public enum FfiTrackStatus: Equatable, Hashable {

    /**
     * The item is known to the queue but loading has not started.
     */
    case pending
    /**
     * The item is actively loading.
     */
    case loading
    /**
     * Loading is progressing slowly enough to be user-visible.
     */
    case slow
    /**
     * The item is loaded and ready for playback.
     */
    case loaded
    /**
     * Loading or playback failed with a native error message.
     */
    case failed(reason: String
    )
    /**
     * The item has already been consumed by playback.
     */
    case consumed
    /**
     * Loading was cancelled by a newer queue selection.
     */
    case cancelled





}

#if compiler(>=6)
extension FfiTrackStatus: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiTrackStatus: FfiConverterRustBuffer {
    typealias SwiftType = FfiTrackStatus

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiTrackStatus {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        case 1: return .pending

        case 2: return .loading

        case 3: return .slow

        case 4: return .loaded

        case 5: return .failed(reason: try FfiConverterString.read(from: &buf)
        )

        case 6: return .consumed

        case 7: return .cancelled

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiTrackStatus, into buf: inout [UInt8]) {
        switch value {


        case .pending:
            writeInt(&buf, Int32(1))


        case .loading:
            writeInt(&buf, Int32(2))


        case .slow:
            writeInt(&buf, Int32(3))


        case .loaded:
            writeInt(&buf, Int32(4))


        case let .failed(reason):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(reason, into: &buf)


        case .consumed:
            writeInt(&buf, Int32(6))


        case .cancelled:
            writeInt(&buf, Int32(7))

        }
    }
}


